import{_ as t,W as l,X as d,Y as c,$ as e,a0 as n,Z as i,a1 as s,D as o}from"./framework-f38b131a.js";const r={},p=s(`<h1 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h1><ol start="0"><li>先查看自己的硬盘是否被自动挂载</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lsblk
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://blog.kevin2li.top/static/img/c6a060031303902d104d6df4594292a3.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>`,4),g=s(`<p>可以通过查看挂载点目录判断自己的硬盘是否被挂载</p><ol><li>查看磁盘列表</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">fdisk</span> <span class="token parameter variable">-l</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://blog.kevin2li.top/static/img/46b5fee9a80bff9d52984f78f9c78fe4.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>可以根据容量大小判断需要挂载的硬盘名称，后面会用到。</p><figure><img src="https://blog.kevin2li.top/static/img/9a979acc59d1bc997a71ea71b0e7d94b.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>如我这里要挂载的磁盘是 <code>/dev/nvme0n1p3</code></p><ol start="2"><li>挂载磁盘</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 创建挂载点目录(如已存在，可省略)</span>
<span class="token function">mkdir</span> <span class="token parameter variable">-p</span> /media/kevin2li/System

<span class="token comment"># 挂载</span>
<span class="token function">sudo</span> <span class="token function">mount</span> /dev/nvme0n1p3 /media/kevin2li/System
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样就挂载成功了。</p><p>可以通过<code>df -h</code>命令验证：</p><figure><img src="https://blog.kevin2li.top/static/img/8bf7856d612817d0321a8673a2195ace.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><div class="hint-container info"><p class="hint-container-title">取消挂载</p><p>如果要取消挂载可以使用如下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">umount</span> /dev/nvme0n1p3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><ol start="3"><li>开机自动挂载</li></ol><p>查看要挂载的磁盘的UUID和分区类型。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>blkid /dev/nvme0n1p3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://blog.kevin2li.top/static/img/2cdfc13ca50b1f5670cbd46a01bf6c60.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>编辑<code>/etc/fstab</code>文件，在文件尾部追加一行(根据上面查到的信息修改)：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">UUID</span><span class="token operator">=</span>4E30F0C230F0B257 /media/kevin2li/System ntfs defaults <span class="token number">0</span> <span class="token number">0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="hint-container info"><p class="hint-container-title">/etc/fstab字段说明</p><figure><img src="https://blog.kevin2li.top/static/img/6d99ff80165bdf82af9a8c1fa903df0c.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure></div><p>重新加载：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">mount</span> <span class="token parameter variable">-a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h1 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h1>`,23),m={href:"https://cloud.tencent.com/developer/article/1813949",target:"_blank",rel:"noopener noreferrer"},u={href:"https://www.simplified.guide/linux/disk-mount",target:"_blank",rel:"noopener noreferrer"};function v(b,f){const a=o("ExternalLinkIcon");return l(),d("div",null,[p,c(" more "),g,e("ol",null,[e("li",null,[e("a",m,[n("https://cloud.tencent.com/developer/article/1813949"),i(a)])]),e("li",null,[e("a",u,[n("https://www.simplified.guide/linux/disk-mount"),i(a)])])])])}const k=t(r,[["render",v],["__file","Linux挂载硬盘.html.vue"]]);export{k as default};
